import { serve } from "https://deno.land/std@0.208.0/http/server.ts";

const kv = await Deno.openKv();

interface User {
  id: string;
  name: string;
  email: string;
  role: string;
  department: string;
  status: string;
  createdAt: string;
  tags: string[];
}

// Seed some sample data
async function seedData() {
  const users: User[] = [
    { id: "1", name: "Alice Johnson", email: "alice@example.com", role: "admin", department: "engineering", status: "active", createdAt: "2024-01-15", tags: ["lead", "senior"] },
    { id: "2", name: "Bob Smith", email: "bob@example.com", role: "developer", department: "engineering", status: "active", createdAt: "2024-02-20", tags: ["junior"] },
    { id: "3", name: "Carol White", email: "carol@example.com", role: "designer", department: "design", status: "active", createdAt: "2024-03-10", tags: ["senior", "ux"] },
    { id: "4", name: "Dave Brown", email: "dave@example.com", role: "developer", department: "engineering", status: "inactive", createdAt: "2024-01-05", tags: ["senior", "backend"] },
    { id: "5", name: "Eve Davis", email: "eve@example.com", role: "manager", department: "product", status: "active", createdAt: "2024-04-01", tags: ["lead"] },
  ];

  for (const user of users) {
    const atomic = kv.atomic();
    // Primary key
    atomic.set(["users", user.id], user);
    // Secondary indexes for efficient lookups
    atomic.set(["users_by_role", user.role, user.id], user);
    atomic.set(["users_by_department", user.department, user.id], user);
    atomic.set(["users_by_status", user.status, user.id], user);
    atomic.set(["users_by_email", user.email], user);
    // Composite indexes
    atomic.set(["users_by_dept_role", user.department, user.role, user.id], user);
    atomic.set(["users_by_dept_status", user.department, user.status, user.id], user);
    // Tag indexes
    for (const tag of user.tags) {
      atomic.set(["users_by_tag", tag, user.id], user);
    }
    await atomic.commit();
  }
}

function buildKvKey(params: Record<string, string>): Deno.KvKey {
  const { id, role, department, status, email, tag } = params;

  // Direct ID lookup
  if (id) {
    return ["users", id];
  }

  // Email lookup (unique index)
  if (email) {
    return ["users_by_email", email];
  }

  // Composite index: department + role
  if (department && role) {
    return ["users_by_dept_role", department, role];
  }

  // Composite index: department + status
  if (department && status) {
    return ["users_by_dept_status", department, status];
  }

  // Single filter indexes
  if (role) {
    return ["users_by_role", role];
  }
  if (department) {
    return ["users_by_department", department];
  }
  if (status) {
    return ["users_by_status", status];
  }
  if (tag) {
    return ["users_by_tag", tag];
  }

  // Default: list all users
  return ["users"];
}

function isDirectLookupKey(params: Record<string, string>): boolean {
  return !!(params.id || params.email);
}

async function searchUsers(params: Record<string, string>): Promise<{ results: User[]; keyUsed: string; count: number }> {
  const key = buildKvKey(params);
  const keyString = JSON.stringify(key);
  const results: User[] = [];

  if (isDirectLookupKey(params)) {
    // Direct single-record lookup
    const entry = await kv.get<User>(key);
    if (entry.value) {
      results.push(entry.value);
    }
  } else {
    // Prefix scan for range queries
    const iter = kv.list<User>({ prefix: key as unknown as Deno.KvKey });
    const limit = params.limit ? parseInt(params.limit) : 100;
    const offset = params.offset ? parseInt(params.offset) : 0;
    let count = 0;

    for await (const entry of iter) {
      if (count >= offset && results.length < limit) {
        if (entry.value) {
          // Apply additional in-memory filters if needed
          let match = true;

          if (params.name) {
            match = match && entry.value.name.toLowerCase().includes(params.name.toLowerCase());
          }
          if (params.created_after) {
            match = match && entry.value.createdAt >= params.created_after;
          }
          if (params.created_before) {
            match = match && entry.value.createdAt <= params.created_before;
          }

          if (match) {
            results.push(entry.value);
          }
        }
      }
      count++;
    }
  }

  // Sort if requested
  if (params.sort_by) {
    const sortField = params.sort_by as keyof User;
    const sortOrder = params.sort_order === "desc" ? -1 : 1;
    results.sort((a, b) => {
      const aVal = a[sortField];
      const bVal = b[sortField];
      if (typeof aVal === "string" && typeof bVal === "string") {
        return aVal.localeCompare(bVal) * sortOrder;
      }
      return 0;
    });
  }

  return { results, keyUsed: keyString, count: results.length };
}

async function createUser(user: Omit<User, "createdAt">): Promise<User> {
  const fullUser: User = {
    ...user,
    createdAt: new Date().toISOString().split("T")[0],
    tags: user.tags || [],
  };

  const atomic = kv.atomic();
  atomic.set(["users", fullUser.id], fullUser);
  atomic.set(["users_by_role", fullUser.role, fullUser.id], fullUser);
  atomic.set(["users_by_department", fullUser.department, fullUser.id], fullUser);
  atomic.set(["users_by_status", fullUser.status, fullUser.id], fullUser);
  atomic.set(["users_by_email", fullUser.email], fullUser);
  atomic.set(["users_by_dept_role", fullUser.department, fullUser.role, fullUser.id], fullUser);
  atomic.set(["users_by_dept_status", fullUser.department, fullUser.status, fullUser.id], fullUser);
  for (const tag of fullUser.tags) {
    atomic.set(["users_by_tag", tag, fullUser.id], fullUser);
  }

  const result = await atomic.commit();
  if (!result.ok) {
    throw new Error("Failed to create user");
  }
  return fullUser;
}

async function updateUser(id: string, updates: Partial<User>): Promise<User | null> {
  const existing = await kv.get<User>(["users", id]);
  if (!existing.value) return null;

  const oldUser = existing.value;
  const updatedUser: User = { ...oldUser, ...updates, id };

  const atomic = kv.atomic();

  // Remove old indexes if relevant fields changed
  if (updates.role && updates.role !== oldUser.role) {
    atomic.delete(["users_by_role", oldUser.role, id]);
    atomic.delete(["users_by_dept_role", oldUser.department, oldUser.role, id]);
  }
  if (updates.department && updates.department !== oldUser.department) {
    atomic.delete(["users_by_department", oldUser.department, id]);
    atomic.delete(["users_by_dept_role", oldUser.department, oldUser.role, id]);
    atomic.delete(["users_by_dept_status", oldUser.department, oldUser.status, id]);
  }
  if (updates.status && updates.status !== oldUser.status) {
    atomic.delete(["users_by_status", oldUser.status, id]);
    atomic.delete(["users_by_dept_status", oldUser.department, oldUser.status, id]);
  }
  if (updates.email && updates.email !== oldUser.email) {
    atomic.delete(["users_by_email", oldUser.email]);
  }
  if (updates.tags) {
    for (const tag of oldUser.tags) {
      atomic.delete(["users_by_tag", tag, id]);
    }
  }

  // Set new indexes
  atomic.set(["users", id], updatedUser);
  atomic.set(["users_by_role", updatedUser.role, id], updatedUser);
  atomic.set(["users_by_department", updatedUser.department, id], updatedUser);
  atomic.set(["users_by_status", updatedUser.status, id], updatedUser);
  atomic.set(["users_by_email", updatedUser.email], updatedUser);
  atomic.set(["users_by_dept_role", updatedUser.department, updatedUser.role, id], updatedUser);
  atomic.set(["users_by_dept_status", updatedUser.department, updatedUser.status, id], updatedUser);
  for (const tag of updatedUser.tags) {
    atomic.set(["users_by_tag", tag, id], updatedUser);
  }

  const result = await atomic.commit();
  if (!result.ok) throw new Error("Failed to update user");
  return updatedUser;
}

async function deleteUser(id: string): Promise<boolean> {
  const existing = await kv.get<User>(["users", id]);
  if (!existing.value) return false;

  const user = existing.value;
  const atomic = kv.atomic();

  atomic.delete(["users", id]);
  atomic.delete(["users_by_role", user.role, id]);
  atomic.delete(["users_by_department", user.department, id]);
  atomic.delete(["users_by_status", user.status, id]);
  atomic.delete(["users_by_email", user.email]);
  atomic.delete(["users_by_dept_role", user.department, user.role, id]);
  atomic.delete(["users_by_dept_status", user.department, user.status, id]);
  for (const tag of user.tags) {
    atomic.delete(["users_by_tag", tag, id]);
  }

  const result = await atomic.commit();
  return result.ok;
}

function jsonResponse(data: unknown, status = 200): Response {
  return new Response(JSON.stringify(data, null, 2), {
    status,
    headers: {
      "Content-Type": "application/json",
      "Access-Control-Allow-Origin": "*",
      "Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
      "Access-Control-Allow-Headers": "Content-Type",
    },
  });
}

function errorResponse(message: string, status = 400): Response {
  return jsonResponse({ error: message }, status);
}

